import React, { useState } from 'react';
import '../styles/ProgramAvatar.css';

// ─── Shop Inventory ───────────────────────────────────────────────────────────
const SHOP_ITEMS = {
  face: [
    { id: 'f1', label: 'Soft Round',    color: '#F4C2C2', owned: true  },
    { id: 'f2', label: 'Sharp Jaw',     color: '#F9D5A7', owned: true  },
    { id: 'f3', label: 'Oval',          color: '#C8E6C9', owned: true  },
    { id: 'f4', label: 'Heart',         color: '#BBDEFB', owned: false },
    { id: 'f5', label: 'Cat-like',      color: '#E1BEE7', owned: false },
    { id: 'f6', label: 'Fox',           color: '#FFE0B2', owned: false },
  ],
  hair: [
    { id: 'h1', label: 'Short Spiky',   color: '#8B4513', owned: true  },
    { id: 'h2', label: 'Long Straight', color: '#2C1810', owned: true  },
    { id: 'h3', label: 'Wavy',          color: '#DAA520', owned: true  },
    { id: 'h4', label: 'Twin Tails',    color: '#C0392B', owned: false },
    { id: 'h5', label: 'Ahoge',         color: '#8E44AD', owned: false },
    { id: 'h6', label: 'Wild Mane',     color: '#1C1C1C', owned: false },
  ],
  skin: [
    { id: 's1', label: 'Fair',          color: '#FFDAB9', owned: true  },
    { id: 's2', label: 'Light',         color: '#F5CBA7', owned: true  },
    { id: 's3', label: 'Medium',        color: '#E59866', owned: true  },
    { id: 's4', label: 'Tan',           color: '#CA8A5A', owned: false },
    { id: 's5', label: 'Mystic Blue',   color: '#90CAF9', owned: false },
    { id: 's6', label: 'Shadow',        color: '#7E57C2', owned: false },
  ],
  hairColor: [
    { id: 'hc1', label: 'Black',        color: '#1C1C1C', owned: true  },
    { id: 'hc2', label: 'Brown',        color: '#8B4513', owned: true  },
    { id: 'hc3', label: 'Blonde',       color: '#FFD700', owned: true  },
    { id: 'hc4', label: 'Red',          color: '#C0392B', owned: false },
    { id: 'hc5', label: 'Purple',       color: '#8E44AD', owned: false },
    { id: 'hc6', label: 'Blue',         color: '#2980B9', owned: false },
    { id: 'hc7', label: 'Pink',         color: '#FF69B4', owned: false },
    { id: 'hc8', label: 'White',        color: '#ECEFF1', owned: false },
  ],
  pets: [
    { id: 'p1', label: 'Fire Dragon',   color: '#FF6B35', emoji: '🐉', owned: true  },
    { id: 'p2', label: 'Ice Dragon',    color: '#74D7F7', emoji: '🐲', owned: true  },
    { id: 'p3', label: 'Shadow Drake',  color: '#7E57C2', emoji: '🦎', owned: false },
    { id: 'p4', label: 'Golden Wyvern', color: '#FFD700', emoji: '✨', owned: false },
    { id: 'p5', label: 'Storm Drake',   color: '#90CAF9', emoji: '⚡', owned: false },
    { id: 'p6', label: 'Void Dragon',   color: '#1C1C1C', emoji: '🌑', owned: false },
  ],
};

const CATEGORY_META = [
  { key: 'face',      label: 'FACE',       icon: '😊' },
  { key: 'hair',      label: 'HAIR',       icon: '💇' },
  { key: 'skin',      label: 'SKIN',       icon: '✋' },
  { key: 'hairColor', label: 'HAIR COLOR', icon: '🎨' },
  { key: 'pets',      label: 'PETS',       icon: '🐉' },
];

// ─── SVG Avatar ───────────────────────────────────────────────────────────────
const AvatarPreview = ({ selections }) => {
  const skin      = SHOP_ITEMS.skin.find(s => s.id === selections.skin)?.color      || '#FFDAB9';
  const hairCol   = SHOP_ITEMS.hairColor.find(h => h.id === selections.hairColor)?.color || '#8B4513';
  const hairStyle = SHOP_ITEMS.hair.find(h => h.id === selections.hair)?.label      || 'Short Spiky';
  const pet       = SHOP_ITEMS.pets.find(p => p.id === selections.pets);

  return (
    <div className="avatar-preview-wrapper">
      {pet && (
        <div className="pet-float" style={{ background: pet.color + '33', borderColor: pet.color }}>
          <span className="pet-emoji-big">{pet.emoji}</span>
          <span className="pet-name-small">{pet.label}</span>
        </div>
      )}

      <svg viewBox="0 0 240 290" width="200" height="200" xmlns="http://www.w3.org/2000/svg">
        {/* Body */}
        <ellipse cx="120" cy="272" rx="72" ry="36" fill={skin} opacity="0.5" />
        {/* Neck */}
        <rect x="108" y="194" width="24" height="32" rx="10" fill={skin} />

        {/* Hair back */}
        {hairStyle === 'Short Spiky' && <>
          <ellipse cx="120" cy="88" rx="64" ry="32" fill={hairCol} />
          <polygon points="90,68 84,44 102,66"  fill={hairCol} />
          <polygon points="110,62 108,36 124,61" fill={hairCol} />
          <polygon points="130,62 132,36 148,64" fill={hairCol} />
          <polygon points="150,68 156,44 164,70" fill={hairCol} />
        </>}
        {hairStyle === 'Long Straight' && <>
          <ellipse cx="120" cy="88" rx="64" ry="32" fill={hairCol} />
          <rect x="56"  y="104" width="20" height="115" rx="10" fill={hairCol} />
          <rect x="164" y="104" width="20" height="115" rx="10" fill={hairCol} />
        </>}
        {hairStyle === 'Wavy' && <>
          <ellipse cx="120" cy="88" rx="64" ry="32" fill={hairCol} />
          <path d="M56 110 Q44 140 58 165 Q44 190 58 218" stroke={hairCol} strokeWidth="18" fill="none" strokeLinecap="round"/>
          <path d="M184 110 Q196 140 182 165 Q196 190 182 218" stroke={hairCol} strokeWidth="18" fill="none" strokeLinecap="round"/>
        </>}
        {hairStyle === 'Twin Tails' && <>
          <ellipse cx="120" cy="88" rx="64" ry="32" fill={hairCol} />
          <ellipse cx="62"  cy="148" rx="16" ry="56" fill={hairCol} transform="rotate(-10 62 148)" />
          <ellipse cx="178" cy="148" rx="16" ry="56" fill={hairCol} transform="rotate(10 178 148)" />
        </>}
        {hairStyle === 'Ahoge' && <>
          <ellipse cx="120" cy="88" rx="64" ry="32" fill={hairCol} />
          <path d="M120 70 Q132 42 118 18 Q110 42 120 70" stroke={hairCol} strokeWidth="8" fill={hairCol} strokeLinecap="round"/>
        </>}
        {hairStyle === 'Wild Mane' && <>
          <ellipse cx="120" cy="88" rx="74" ry="42" fill={hairCol} />
          <ellipse cx="58"  cy="124" rx="24" ry="52" fill={hairCol} />
          <ellipse cx="182" cy="124" rx="24" ry="52" fill={hairCol} />
          <ellipse cx="120" cy="60"  rx="42" ry="22" fill={hairCol} />
        </>}

        {/* Face */}
        <ellipse cx="120" cy="150" rx="58" ry="62" fill={skin} />

        {/* Anime eyes — left */}
        <ellipse cx="98"  cy="140" rx="11" ry="14" fill="white" />
        <ellipse cx="98"  cy="143" rx="8"  ry="10" fill="#1a1a2e" />
        <ellipse cx="98"  cy="143" rx="5"  ry="7"  fill="#3a86ff" opacity="0.7" />
        <circle  cx="93"  cy="138" r="3"   fill="white" />
        <ellipse cx="98"  cy="129" rx="12" ry="4"  fill={hairCol} />

        {/* Anime eyes — right */}
        <ellipse cx="142" cy="140" rx="11" ry="14" fill="white" />
        <ellipse cx="142" cy="143" rx="8"  ry="10" fill="#1a1a2e" />
        <ellipse cx="142" cy="143" rx="5"  ry="7"  fill="#3a86ff" opacity="0.7" />
        <circle  cx="137" cy="138" r="3"   fill="white" />
        <ellipse cx="142" cy="129" rx="12" ry="4"  fill={hairCol} />

        {/* Nose */}
        <path d="M116 163 Q120 169 124 163" stroke="#D4907A" strokeWidth="1.5" fill="none" strokeLinecap="round"/>
        {/* Mouth */}
        <path d="M108 176 Q120 185 132 176" stroke="#E87070" strokeWidth="2.5" fill="none" strokeLinecap="round"/>
        {/* Blush */}
        <ellipse cx="86"  cy="163" rx="12" ry="7" fill="#FFB6C1" opacity="0.45" />
        <ellipse cx="154" cy="163" rx="12" ry="7" fill="#FFB6C1" opacity="0.45" />

        {/* Hair front overlay */}
        <ellipse cx="120" cy="97" rx="62" ry="20" fill={hairCol} opacity="0.9" />
      </svg>
    </div>
  );
};

// ─── Shop Modal ───────────────────────────────────────────────────────────────
const ShopModal = ({ category, currentSelection, onSelect, onClose }) => {
  const items = SHOP_ITEMS[category.key] || [];
  const meta  = CATEGORY_META.find(m => m.key === category.key);

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-box" onClick={e => e.stopPropagation()}>

        <div className="modal-header">
          <span className="modal-header-icon">{meta.icon}</span>
          <h2 className="modal-title">{meta.label}</h2>
          <button className="modal-close-btn" onClick={onClose}>✕</button>
        </div>

        <p className="modal-subtitle">Tap an owned item to equip it on your avatar</p>

        <div className="modal-grid">
          {items.map(item => (
            <div
              key={item.id}
              className={`modal-item ${!item.owned ? 'locked' : ''} ${currentSelection === item.id ? 'selected' : ''}`}
              onClick={() => item.owned && onSelect(item.id)}
              title={!item.owned ? 'Purchase from Shop to unlock' : item.label}
            >
              <div className="modal-item-icon" style={{ background: item.color }}>
                {category.key === 'pets' && (
                  <span className="modal-pet-emoji">{item.emoji}</span>
                )}
                {!item.owned && <div className="lock-overlay">🔒</div>}
                {currentSelection === item.id && item.owned && (
                  <div className="equipped-check">✓</div>
                )}
              </div>
              <span className="modal-item-label">{item.label}</span>
              {!item.owned
                ? <span className="locked-tag">Locked</span>
                : <span className="owned-tag">Owned</span>
              }
            </div>
          ))}
        </div>

        <div className="modal-footer">
          <p className="modal-hint">🔒 Visit the <strong>Shop</strong> to unlock more items</p>
          <button className="modal-done-btn" onClick={onClose}>Done</button>
        </div>
      </div>
    </div>
  );
};

// ─── Category Card ────────────────────────────────────────────────────────────
const CategoryCard = ({ meta, selections, onMoreClick }) => {
  const items    = SHOP_ITEMS[meta.key] || [];
  const selected = items.find(i => i.id === selections[meta.key]);
  const previews = items.filter(i => i.owned).slice(0, 2);

  return (
    <div className="card category-card" data-testid={`${meta.key}-card`}>
      <h3 className="category-title">{meta.label}</h3>
      <div className="category-previews">
        {previews.map(item => (
          <div
            key={item.id}
            className="category-preview-circle"
            style={{ background: item.color }}
          >
            {meta.key === 'pets' && <span className="preview-emoji">{item.emoji}</span>}
          </div>
        ))}
      </div>
      {selected && (
        <p className="category-equipped">
          Equipped: <strong>{selected.label}</strong>
        </p>
      )}
      <button
        className="more-button"
        onClick={() => onMoreClick(meta)}
        data-testid={`${meta.key}-more-btn`}
      >
        More
      </button>
    </div>
  );
};

// ─── Page ─────────────────────────────────────────────────────────────────────
const ProgramAvatar = () => {
  const [avatarName, setAvatarName]   = useState('');
  const [activeModal, setActiveModal] = useState(null);
  const [selections, setSelections]   = useState({
    face:      'f1',
    hair:      'h1',
    skin:      's1',
    hairColor: 'hc1',
    pets:      null,
  });
  const [saved, setSaved] = useState(false);

  const handleSelect = (key, id) => {
    setSelections(prev => ({ ...prev, [key]: id }));
    setActiveModal(null);
  };

  return (
    <div className="page-container">
      <div className="avatar-page-layout">

        {/* Avatar Preview */}
        <div className="card avatar-preview-card" data-testid="avatar-main">
          <h2 className="section-title">Your Avatar</h2>
          <div className="avatar-display">
            <AvatarPreview selections={selections} />
            <input
              type="text"
              placeholder="Enter your Avatar name......"
              value={avatarName}
              onChange={e => { setAvatarName(e.target.value); setSaved(false); }}
              className="avatar-name-input"
              data-testid="avatar-name-input"
            />
            <button
              className="create-button"
              onClick={() => setSaved(true)}
              data-testid="avatar-create-btn"
            >
              CREATE AVATAR
            </button>
            {saved && avatarName && (
              <div className="avatar-saved-badge">✅ {avatarName} saved!</div>
            )}
          </div>
        </div>

        {/* Category Cards */}
        <div className="categories-panel">
          {CATEGORY_META.map(meta => (
            <CategoryCard
              key={meta.key}
              meta={meta}
              selections={selections}
              onMoreClick={setActiveModal}
            />
          ))}
        </div>
      </div>

      {/* Modal */}
      {activeModal && (
        <ShopModal
          category={activeModal}
          currentSelection={selections[activeModal.key]}
          onSelect={id => handleSelect(activeModal.key, id)}
          onClose={() => setActiveModal(null)}
        />
      )}
    </div>
  );
};

export default ProgramAvatar;
